svg.script:
(function () {
  var svg = document.currentScript && document.currentScript.ownerSVGElement;
  var pointerDocuments = [document];
  var reducedMotion;

  if (!svg) {
    return;
  }

  reducedMotion = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  if (reducedMotion) {
    return;
  }

  try {
    if (window.parent && window.parent !== window && window.parent.document) {
      pointerDocuments.push(window.parent.document);
    }
  } catch (error) {}

  var faceCenterX = 31.015;
  var faceCenterY = 28.758;
  var viewBoxSize = 61;
  var enterInfluencePx = 300;
  var leaveInfluencePx = 360;
  var fullStrengthUntilPx = 220;
  var maxX = 2.05;
  var maxY = 1.2;
  var frame = null;
  var lastEvent = null;
  var lastEventUsesParentCoords = false;
  var isNear = false;
  var lastNearWinkAt = 0;
  var nearWinkCooldownMs = 9000;
  var blinkTimeout = null;
  var laserTimeout = null;
  var laserEyes = {
    left: { x: 24.494, y: 28.758 },
    right: { x: 37.536, y: 28.758 }
  };
  var requestFrame = window.requestAnimationFrame || function (callback) {
    return window.setTimeout(callback, 16);
  };

  function setOffset(x, y) {
    svg.style.setProperty('--purio-eye-x', x.toFixed(2) + 'px');
    svg.style.setProperty('--purio-eye-y', y.toFixed(2) + 'px');
  }

  function resetEyes() {
    lastEvent = null;
    isNear = false;
    setOffset(0, 0);
  }

  function getFrameRect() {
    try {
      if (window.frameElement) {
        return window.frameElement.getBoundingClientRect();
      }
    } catch (error) {}

    return null;
  }

  function getFaceScreenCenter(useParentCoords) {
    var rect = svg.getBoundingClientRect();
    var frameRect = useParentCoords ? getFrameRect() : null;
    var x = rect.left + (rect.width * (faceCenterX / viewBoxSize));
    var y = rect.top + (rect.height * (faceCenterY / viewBoxSize));

    if (frameRect) {
      x += frameRect.left;
      y += frameRect.top;
    }

    return { x: x, y: y };
  }

  function updateEyes() {
    var center;
    var dx;
    var dy;
    var distance;
    var fade;

    frame = null;

    if (!lastEvent) {
      return;
    }

    center = getFaceScreenCenter(lastEventUsesParentCoords);
    dx = lastEvent.clientX - center.x;
    dy = lastEvent.clientY - center.y;
    distance = Math.sqrt((dx * dx) + (dy * dy));

    if (distance < 0.01) {
      setOffset(0, 0);
      return;
    }

    if (distance > leaveInfluencePx) {
      resetEyes();
      return;
    }

    if (distance > enterInfluencePx) {
      setOffset(0, 0);
      return;
    }

    if (!isNear) {
      isNear = true;
      playNearWink();
    }

    fade = 1;
    if (distance > fullStrengthUntilPx) {
      fade = Math.max(0, 1 - ((distance - fullStrengthUntilPx) / (enterInfluencePx - fullStrengthUntilPx)));
    }

    setOffset((dx / distance) * maxX * fade, (dy / distance) * maxY * fade);
  }

  function handlePointerMove(event) {
    var eventDocument = event.target && event.target.ownerDocument ? event.target.ownerDocument : document;

    lastEvent = event;
    lastEventUsesParentCoords = eventDocument !== document;

    if (frame === null) {
      frame = requestFrame(updateEyes);
    }
  }

  function clearRandomBlink() {
    if (blinkTimeout !== null) {
      window.clearTimeout(blinkTimeout);
      blinkTimeout = null;
    }
  }

  function scheduleRandomBlink() {
    clearRandomBlink();
    blinkTimeout = window.setTimeout(playRandomBlink, 3600 + (Math.random() * 7600));
  }

  function playRandomBlink() {
    if (svg.classList.contains('is-near-winking')) {
      scheduleRandomBlink();
      return;
    }

    svg.classList.remove('is-random-blinking');
    svg.getBoundingClientRect();
    svg.classList.add('is-random-blinking');

    window.setTimeout(function () {
      svg.classList.remove('is-random-blinking');
      scheduleRandomBlink();
    }, 260);
  }

  function playNearWink() {
    var now = Date.now();

    if (svg.classList.contains('is-near-winking')) {
      return;
    }

    if (now - lastNearWinkAt < nearWinkCooldownMs) {
      return;
    }

    lastNearWinkAt = now;
    svg.classList.remove('is-near-winking');
    svg.getBoundingClientRect();
    svg.classList.add('is-near-winking');

    window.setTimeout(function () {
      svg.classList.remove('is-near-winking');
    }, 700);
  }

  function formatLaserPath(start, end) {
    return 'M' + start.x.toFixed(3) + ' ' + start.y.toFixed(3) + 'L' + end.x.toFixed(3) + ' ' + end.y.toFixed(3);
  }

  function getLaserEdgePoint(start, offsetX, offsetY) {
    var min = 0.7;
    var max = 60.3;
    var candidates = [];
    var t;

    if (offsetX > 0) {
      candidates.push((max - start.x) / offsetX);
    } else if (offsetX < 0) {
      candidates.push((min - start.x) / offsetX);
    }

    if (offsetY > 0) {
      candidates.push((max - start.y) / offsetY);
    } else if (offsetY < 0) {
      candidates.push((min - start.y) / offsetY);
    }

    t = candidates.reduce(function (best, candidate) {
      if (candidate > 0 && candidate < best) {
        return candidate;
      }

      return best;
    }, 1);

    return {
      x: start.x + (offsetX * t),
      y: start.y + (offsetY * t)
    };
  }

  function setLaserPathAndFlame(eyeName, offsetX, offsetY) {
    var start = laserEyes[eyeName];
    var end = {
      x: start.x + offsetX,
      y: start.y + offsetY
    };
    var edge = getLaserEdgePoint(start, offsetX, offsetY);
    var flame = svg.querySelector('[data-laser-flame="' + eyeName + '"]');
    var angle = Math.atan2(offsetY, offsetX) * (180 / Math.PI);

    svg.querySelectorAll('[data-laser-eye="' + eyeName + '"]').forEach(function (laser) {
      laser.setAttribute('d', formatLaserPath(start, end));
    });

    if (flame) {
      flame.setAttribute('transform', 'translate(' + edge.x.toFixed(3) + ' ' + edge.y.toFixed(3) + ') rotate(' + angle.toFixed(2) + ')');
    }
  }

  function setLaserDirection(event) {
    var targetEvent = event && typeof event.clientX === 'number' ? event : lastEvent;
    var eventDocument = targetEvent && targetEvent.target && targetEvent.target.ownerDocument ? targetEvent.target.ownerDocument : document;
    var usesParentCoords = targetEvent ? eventDocument !== document : lastEventUsesParentCoords;
    var center;
    var dx;
    var dy;
    var distance;
    var length = 78;
    var offsetX;
    var offsetY;

    if (!targetEvent) {
      offsetX = length;
      offsetY = 0;
    } else {
      center = getFaceScreenCenter(usesParentCoords);
      dx = targetEvent.clientX - center.x;
      dy = targetEvent.clientY - center.y;
      distance = Math.sqrt((dx * dx) + (dy * dy));

      if (distance < 0.01) {
        dx = 1;
        dy = 0;
        distance = 1;
      }

      offsetX = (dx / distance) * length;
      offsetY = (dy / distance) * length;
    }

    setLaserPathAndFlame('left', offsetX, offsetY);
    setLaserPathAndFlame('right', offsetX, offsetY);
  }

  function playLaserEyes(event) {
    if (laserTimeout !== null) {
      window.clearTimeout(laserTimeout);
      laserTimeout = null;
    }

    setLaserDirection(event);
    svg.classList.remove('is-laser-eyed');
    svg.getBoundingClientRect();
    svg.classList.add('is-laser-eyed');

    laserTimeout = window.setTimeout(function () {
      svg.classList.remove('is-laser-eyed');
      laserTimeout = null;
    }, 680);
  }

  pointerDocuments.forEach(function (pointerDocument) {
    pointerDocument.addEventListener('pointermove', handlePointerMove, { passive: true });
    pointerDocument.addEventListener('pointerleave', resetEyes);
  });

  svg.addEventListener('click', playLaserEyes);

  window.addEventListener('blur', function () {
    resetEyes();
    scheduleRandomBlink();
  });

  scheduleRandomBlink();
}());
